package telsuko.prac;

public class EvenNumbers {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		System.out.println("Even numbers are: ");
		int numbers=100;
		for(int i=1;i<=numbers;i++) {
			if(i%2==0) {
				System.out.println(i);
			}
		}
	}

}
